/**
 * Measures the cold-safe exact-filter rewrite against the identical query with exactly that optimizer stage removed.
 * Setup verifies the expected optimized shape before any measurements are accepted.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 3, time = 1, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode(Mode.AverageTime)
@Fork(value = 3, jvmArgs = { "-Xms1G", "-Xmx3G" })
@Measurement(iterations = 5, time = 1, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MICROSECONDS)
public class ExactFilterPipelineBenchmark {

	private static final String EX = "http://example.com/exact-filter/";

	@Param({ "candidatePipeline", "baselinePipeline" })
	public String mode;

	@Param({ "1", "32", "64", "65" })
	public int distinctValueCount;

	@Param({ "131072" })
	public int rowCount;

	private File dataDir;
	private SailRepository repository;
	private String query;

	@Setup(Level.Trial)
	public void setUp() throws IOException {
		dataDir = Files.newTemporaryFolder();
		LmdbStore store = new LmdbStore(dataDir,
				new LmdbStoreConfig("spoc,posc,ospc").setSketchEstimatorEnabled(true));
		repository = new SailRepository(store);
		BenchmarkJoinEstimatorSupport.prepareEstimatorForBulkLoad(repository, store);
		loadData();
		BenchmarkJoinEstimatorSupport.persistEstimatorAfterBulkLoad(repository, store);
		store.setEvaluationStrategyFactory(new ExactFilterPipelineBenchmarkEvaluationStrategyFactory(
				"candidatePipeline".equals(mode)));

		query = exactFilterQuery();
		String optimizedPlan;
		try (SailRepositoryConnection connection = repository.getConnection()) {
			optimizedPlan = connection.prepareTupleQuery(QueryLanguage.SPARQL, query)
					.explain(Explanation.Level.Optimized)
					.toString();
		}
		boolean shouldRewrite = "candidatePipeline".equals(mode) && distinctValueCount <= 64;
		boolean hasValues = optimizedPlan.contains("BindingSetAssignment");
		if (hasValues != shouldRewrite) {
			throw new IllegalStateException(mode + " with " + distinctValueCount
					+ " constants produced an unexpected optimized shape:\n" + optimizedPlan);
		}
	}

	private void loadData() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI name = vf.createIRI(EX, "name");
			connection.begin();
			for (int i = 0; i < rowCount; i++) {
				connection.add(vf.createIRI(EX, "subject/" + i), name,
						vf.createLiteral("value-" + (i % distinctValueCount)));
			}
			connection.commit();
		}
	}

	private String exactFilterQuery() {
		StringBuilder values = new StringBuilder();
		for (int i = 0; i < distinctValueCount; i++) {
			if (i > 0) {
				values.append(", ");
			}
			values.append('\"').append("value-").append(i).append('\"');
		}
		values.append(", \"value-0\"");
		return "SELECT (COUNT(?s) AS ?count) WHERE { ?s <" + EX + "name> ?name . FILTER(?name IN ("
				+ values + ")) }";
	}

	@Benchmark
	public long executeQuery() {
		try (SailRepositoryConnection connection = repository.getConnection();
				var result = connection.prepareTupleQuery(QueryLanguage.SPARQL, query).evaluate()) {
			if (!result.hasNext()) {
				throw new IllegalStateException("Exact-filter benchmark did not produce its aggregate row");
			}
			Literal count = (Literal) result.next().getValue("count");
			if (result.hasNext() || count.longValue() != rowCount) {
				throw new IllegalStateException(mode + ": expected count " + rowCount + " but got " + count);
			}
			return count.longValue();
		}
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		if (repository != null) {
			repository.shutDown();
		}
		if (dataDir != null) {
			FileUtil.deleteDir(dataDir);
		}
	}
}
